22	// newInstallCommand creates the "ddx install <name>" command.
23	func (f *CommandFactory) newInstallCommand() *cobra.Command {
24		cmd := &cobra.Command{
25			Use:   "install <name>",
26			Short: "Install a package or resource",
27			Long: `Install a package or resource from the DDx registry.
28	
29	Without --global, installs into the current project:
30	  - In-tree mode (.ddx/ exists): <project>/.ddx/plugins/<name>/
31	  - Convention mode (no .ddx/): ${XDG_DATA_HOME}/ddx/projects/<identity>/plugins/<name>/
32	Skill links are created under <project>/.claude/skills/ and <project>/.agents/skills/.
33	
34	With --global, installs into the machine-wide DDx plugin tree:
35	  ${XDG_DATA_HOME}/ddx/global/plugins/<name>/
36	Skill links are created under ~/.claude/skills/ and ~/.agents/skills/.
37	
38	Examples:
39	  ddx install helix                        # Install HELIX workflow (project-local)
40	  ddx install helix --global               # Install HELIX workflow (machine-wide)
41	  ddx install helix --force                # Reinstall even if already up to date
42	  ddx plugin install helix --local ../helix --force
43	  ddx install persona/strict-code-reviewer # Install a single persona`,
44			Args: cobra.ExactArgs(1),
45			RunE: f.runInstall,
46		}
47		cmd.Flags().BoolP("force", "f", false, "Reinstall even if already at the latest version")
48		cmd.Flags().String("local", "", "Install from a local directory instead of the registry")
49		cmd.Flags().Bool("global", false, "Install into the machine-wide global plugin tree (${XDG_DATA_HOME}/ddx/global/)")
50		cmd.Flags().Bool("silent", false, "Suppress all output except errors")
51		return cmd
52	}
