54	func (f *CommandFactory) runInstall(cmd *cobra.Command, args []string) error {
55		out := cmd.OutOrStdout()
56		force, _ := cmd.Flags().GetBool("force")
57		global, _ := cmd.Flags().GetBool("global")
58		if silent, _ := cmd.Flags().GetBool("silent"); silent {
59			out = io.Discard
60		}
61		name := args[0]
62	
63		// Ensure install operations resolve relative paths against the project
64		// root (WorkingDir), not the caller's cwd. This prevents creating stale
65		// .ddx/ workspaces in subdirectories.
66		if f.WorkingDir != "" {
67			origDir, _ := os.Getwd()
68			if origDir != f.WorkingDir {
69				if err := os.Chdir(f.WorkingDir); err == nil {
70					defer func() { _ = os.Chdir(origDir) }()
71				}
72			}
73		}
74	
75		// Handle --local: install from a local directory instead of registry.
76		if localPath, _ := cmd.Flags().GetString("local"); localPath != "" {
77			return f.installLocal(name, localPath, force, global, out)
78		}
79	
80		if registry.IsResourcePath(name) {
81			// Individual resource install (e.g. "persona/strict-code-reviewer")
82			fmt.Fprintf(out, "Installing resource %s...\n", name)
83			entry, err := registry.InstallResource(name)
84			if err != nil {
85				return fmt.Errorf("install resource: %w", err)
86			}
87	
88			state, err := registry.LoadState()
89			if err != nil {
90				return fmt.Errorf("loading state: %w", err)
91			}
92			state.AddOrUpdate(entry)
93			if err := registry.SaveState(state); err != nil {
94				return fmt.Errorf("saving state: %w", err)
95			}
96	
97			fmt.Fprintf(out, "Installed %s\n", name)
98			return nil
99		}
100	
101		// Package install (e.g. "helix").
102		// Determine install root and skill directories based on global vs project mode.
103		installRoot, agentSkillsDir, claudeSkillsDir, err := f.resolveInstallDirs(global)
104		if err != nil {
105			return err
106		}
107	
108		// Select the correct state file for global vs project installs.
109		loadState, saveState := selectInstallState(global)
110	
111		reg := registry.BuiltinRegistry()
112		pkg, err := reg.Find(name)
113		if err != nil {
114			return err
115		}
116	
117		// Fetch actual latest version from GitHub (overrides hardcoded registry version).
118		if release, err := update.FetchLatestReleaseForRepo(pkg.Source); err == nil {
119			pkg.Version = strings.TrimPrefix(release.TagName, "v")
120		}
121	
122		// Check if already installed at the latest version.
123		state, err := loadState()
124		if err == nil {
125			for _, e := range state.Installed {
126				if e.Name == name {
127					if e.Version == pkg.Version {
128						if !force {
129							fmt.Fprintf(out, "%s %s is already up to date\n", e.Name, e.Version)
130							return nil
131						}
132						fmt.Fprintf(out, "Reinstalling %s %s...\n", e.Name, e.Version)
133					} else {
134						fmt.Fprintf(out, "Updating %s from %s to %s...\n", e.Name, e.Version, pkg.Version)
135					}
136				}
137			}
138		}
139	
140		// Capture old file list before installing so we can remove stale files.
141		var oldFiles []string
142		if state != nil {
143			if old := state.FindInstalled(name); old != nil {
144				oldFiles = append([]string{}, old.Files...)
145			}
146		}
147	
148		fmt.Fprintf(out, "Installing %s %s from %s...\n", pkg.Name, pkg.Version, pkg.Source)
149	
150		// Adjust package targets to use the resolved install root and skill dirs.
151		adjustedPkg := adjustInstallTargets(pkg, name, agentSkillsDir, claudeSkillsDir)
152		entry, err := registry.InstallPackage(adjustedPkg, installRoot)
153		if err != nil {
154			return fmt.Errorf("install package: %w", err)
155		}
156	
157		removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
158		if removed > 0 {
159			fmt.Fprintf(out, "Removed %d stale file(s)\n", removed)
160		}
161	
162		state, stateErr := loadState()
163		if stateErr != nil {
164			return fmt.Errorf("loading state: %w", stateErr)
165		}
166		state.AddOrUpdate(entry)
167		if err := saveState(state); err != nil {
168			return fmt.Errorf("saving state: %w", err)
169		}
170	
171		fmt.Fprintf(out, "Installed %s %s (%d file(s))\n", pkg.Name, pkg.Version, len(entry.Files))
172	
173		// Auto-commit skill links and other trackable project changes (project installs only).
174		if !global {
175			commitPluginChanges(name, pkg.Version)
176		}
177	
178		return nil
179	}
