181	// resolveInstallDirs returns the install root directory and agent/claude skill
182	// directories for either a global or project-local install. For project installs,
183	// the existing in-tree .ddx directory wins when present, otherwise we fall back
184	// to the convention root.
185	func (f *CommandFactory) resolveInstallDirs(global bool) (installRoot, agentSkillsDir, claudeSkillsDir string, err error) {
186		if global {
187			installRoot = ddxroot.GlobalDir()
188			home, herr := os.UserHomeDir()
189			if herr != nil {
190				return "", "", "", fmt.Errorf("getting home dir: %w", herr)
191			}
192			agentSkillsDir = filepath.Join(home, ".agents", "skills")
193			claudeSkillsDir = filepath.Join(home, ".claude", "skills")
194			return
195		}
196		installRoot = resolveBeadStoreRoot(f.WorkingDir)
197		agentSkillsDir = filepath.Join(f.WorkingDir, ".agents", "skills")
198		claudeSkillsDir = filepath.Join(f.WorkingDir, ".claude", "skills")
199		return
200	}
