202	// selectInstallState returns load/save functions for the appropriate state file.
203	func selectInstallState(global bool) (
204		load func() (*registry.InstalledState, error),
205		save func(*registry.InstalledState) error,
206	) {
207		if global {
208			return registry.LoadGlobalState, registry.SaveGlobalState
209		}
210		return registry.LoadState, registry.SaveState
211	}
