213	// adjustInstallTargets returns a shallow copy of pkg with Root.Target overridden
214	// to "plugins/<name>" (relative to installRoot) and Skills targets remapped to
215	// the provided absolute agentSkillsDir/claudeSkillsDir paths.
216	func adjustInstallTargets(pkg *registry.Package, name, agentSkillsDir, claudeSkillsDir string) *registry.Package {
217		adjusted := *pkg
218		adjustedInstall := pkg.Install
219	
220		src := "."
221		if pkg.Install.Root != nil {
222			src = pkg.Install.Root.Source
223		}
224		adjustedInstall.Root = &registry.InstallMapping{
225			Source: src,
226			Target: filepath.Join("plugins", name),
227		}
228	
229		adjustedInstall.Skills = remapSkillTargets(pkg.Install.Skills, agentSkillsDir, claudeSkillsDir)
230		adjusted.Install = adjustedInstall
231		return &adjusted
232	}
233	
234	// remapSkillTargets replaces relative .agents/skills and .claude/skills targets
235	// with the provided absolute directory paths.
236	func remapSkillTargets(mappings []registry.InstallMapping, agentSkillsDir, claudeSkillsDir string) []registry.InstallMapping {
237		result := make([]registry.InstallMapping, len(mappings))
238		for i, m := range mappings {
239			target := m.Target
240			t := filepath.ToSlash(target)
241			switch {
242			case strings.Contains(t, "agents/skills"):
243				target = strings.TrimRight(agentSkillsDir, "/") + "/"
244			case strings.Contains(t, "claude/skills"):
245				target = strings.TrimRight(claudeSkillsDir, "/") + "/"
246			}
247			result[i] = registry.InstallMapping{
248				Source: m.Source,
249				Target: target,
250			}
251		}
252		return result
253	}
