281	func (f *CommandFactory) runPluginList(cmd *cobra.Command, args []string) error {
282		out := cmd.OutOrStdout()
283		global, _ := cmd.Flags().GetBool("global")
284	
285		loadState, _ := selectInstallState(global)
286		state, err := loadState()
287		if err != nil {
288			return fmt.Errorf("loading state: %w", err)
289		}
290	
291		if len(state.Installed) == 0 {
292			fmt.Fprintln(out, "No plugins installed.")
293			return nil
294		}
295	
296		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
297		fmt.Fprintln(w, "NAME\tVERSION\tTYPE\tSTATUS")
298		for _, e := range state.Installed {
299			status := "ok"
300			if !e.VerifyFiles() {
301				status = "BROKEN"
302			}
303			fmt.Fprintf(w, "%s\t%s\t%s\t%s\n", e.Name, e.Version, string(e.Type), status)
304		}
305		return w.Flush()
306	}
