344	func removeStaleFilesFromInstall(oldFiles []string, newFiles []string) int {
345		if len(oldFiles) == 0 {
346			return 0
347		}
348	
349		newSet := make(map[string]bool, len(newFiles))
350		for _, f := range newFiles {
351			newSet[f] = true
352		}
353	
354		removed := 0
355		for _, f := range oldFiles {
356			if newSet[f] {
357				continue
358			}
359			if installPathContainsAny(f, newFiles) {
360				continue
361			}
362			expanded := registry.ExpandHome(f)
363			if err := os.RemoveAll(expanded); err == nil {
364				removed++
365			}
366		}
367		return removed
368	}
