370	func installPathContainsAny(parent string, files []string) bool {
371		parent = filepath.ToSlash(strings.TrimSuffix(parent, string(filepath.Separator)))
372		parent = strings.TrimSuffix(parent, "/")
373		if parent == "" {
374			return false
375		}
376		prefix := parent + "/"
377		for _, f := range files {
378			f = filepath.ToSlash(f)
379			if strings.HasPrefix(f, prefix) {
380				return true
381			}
382		}
383		return false
384	}
