386	// commitPluginChanges stages and commits plugin-related changes in the working tree.
387	// Non-fatal: if git operations fail (not a repo, nothing to commit), it's silently skipped.
388	func commitPluginChanges(name, version string) {
389		// Stage the project-local plugin tree and the skill copies.
390		paths := []string{ddxroot.JoinRelative("plugins", name) + string(filepath.Separator), ".agents/skills/",
391			".claude/skills/",
392		}
393		ctx := context.Background()
394		for _, p := range paths {
395			if _, err := os.Stat(p); err == nil {
396				gitAdd := internalgit.Command(ctx, "", "add", p)
397				_ = gitAdd.Run()
398			}
399		}
400	
401		// Check if there's anything to commit.
402		status := internalgit.Command(ctx, "", "diff", "--cached", "--quiet")
403		if status.Run() == nil {
404			return // nothing staged
405		}
406	
407		msg := fmt.Sprintf("chore: install %s %s", name, version)
408		gitCommit := internalgit.Command(ctx, "", "commit", "-m", msg)
409		_ = gitCommit.Run()
410	}
