412	func prepareSymlinkTarget(target string, force bool) error {
413		if info, err := os.Lstat(target); err == nil {
414			if info.Mode()&os.ModeSymlink != 0 || force {
415				if err := os.RemoveAll(target); err != nil {
416					return fmt.Errorf("removing existing %s: %w", target, err)
417				}
418				return nil
419			}
420			return fmt.Errorf("%s already exists (use --force to replace)", target)
421		} else if !os.IsNotExist(err) {
422			return fmt.Errorf("checking existing %s: %w", target, err)
423		}
424		return nil
425	}
