427	// installLocal installs a plugin from a local directory as a developer overlay.
428	// When global is true, the plugin root is linked into the machine-wide global
429	// plugin tree and skills are linked into the home-level harness directories.
430	// When global is false, the plugin root and skills land in the project tree
431	// (in-tree mode: <project>/.ddx/plugins/<name>; convention mode: XDG project path).
432	// Local installs intentionally do not update the recorded installed state and
433	// do not auto-commit so the recorded plugin pin remains whatever the project
434	// already declares.
435	func (f *CommandFactory) installLocal(name, localPath string, force bool, global bool, out io.Writer) error {
436		// Resolve to absolute path.
437		absPath, err := filepath.Abs(localPath)
438		if err != nil {
439			return fmt.Errorf("resolving path %s: %w", localPath, err)
440		}
441		if _, err := os.Stat(absPath); os.IsNotExist(err) {
442			return fmt.Errorf("local path does not exist: %s", absPath)
443		}
444	
445		// Load package.yaml when present so local installs honor the manifest
446		// contract. If package.yaml is absent, use the plugin manifest rather than
447		// assuming a repository layout from the package name.
448		reg := registry.BuiltinRegistry()
449		fallbackPkg, _ := reg.Find(name)
450	
451		pkg, manifestMissing, manifestIssues, manifestErr := registry.LoadPackageManifestWithFallback(absPath, fallbackPkg)
452		if manifestMissing {
453			pluginPkg, ok, pluginErr := loadLocalPluginManifestPackage(absPath, name)
454			if pluginErr != nil {
455				return pluginErr
456			}
457			if ok {
458				pkg = pluginPkg
459			} else {
460				pkg = &registry.Package{
461					Name:        name,
462					Version:     "local",
463					Description: "local plugin package",
464					Type:        registry.PackageTypePlugin,
465					Source:      absPath,
466				}
467			}
468		}
469		if manifestErr == nil {
470			if strings.TrimSpace(pkg.Name) != "" && pkg.Name != name {
471				return fmt.Errorf("local package name %q does not match package.yaml name %q", name, pkg.Name)
472			}
473		} else {
474			if os.IsNotExist(manifestErr) && manifestMissing {
475				// Already handled through package.yaml absence fallback above.
476			} else if len(manifestIssues) > 0 {
477				return fmt.Errorf("validating package manifest: %w", manifestErr)
478			} else {
479				return fmt.Errorf("loading package manifest: %w", manifestErr)
480			}
481		}
482	
483		if pkg == nil {
484			pkg = &registry.Package{
485				Name:        name,
486				Version:     "local",
487				Description: "local plugin package",
488				Type:        registry.PackageTypePlugin,
489				Source:      absPath,
490			}
491		}
492	
493		if pkg.Install.Root == nil {
494			pkg.Install.Root = &registry.InstallMapping{
495				Source: ".",
496				Target: fmt.Sprintf(".ddx/plugins/%s", pkg.Name),
497			}
498		}
499	
500		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
501			return fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
502		}
503	
504		projectRoot := f.WorkingDir
505		if projectRoot == "" {
506			projectRoot, _ = os.Getwd()
507		}
508		var oldFiles []string
509		if state, err := registry.LoadState(); err == nil {
510			if old := state.FindInstalled(pkg.Name); old != nil {
511				oldFiles = append([]string{}, old.Files...)
512				_, _ = markLocalInstallOverlay(projectRoot, pkg.Name, oldFiles)
513			}
514		}
515	
516		if issues := filterLocalInstallValidationIssues(absPath, registry.ValidatePackageStructure(absPath, pkg)); len(issues) > 0 {
517			return fmt.Errorf("validating package structure: %s", registry.JoinValidationIssues(issues))
518		}
519	
520		// Determine the actual plugin directory based on global vs project mode.
521		// Global: link into the machine-wide global tree.
522		// Project in-tree: link into <project>/.ddx/plugins/<name>.
523		// Project convention: link into the XDG convention root plugins/<name>.
524		// The FEAT-015 check above already validates that pkg.Install.Root.Target
525		// does not start with "~"; we now override the actual destination path.
526		var pluginDir string
527		if global {
528			pluginDir = filepath.Join(ddxroot.GlobalDir(), "plugins", name)
529		} else {
530			ddxRootDir := resolveBeadStoreRoot(f.WorkingDir)
531			pluginDir = filepath.Join(ddxRootDir, "plugins", name)
532		}
533	
534		if err := prepareSymlinkTarget(pluginDir, force); err != nil {
535			return err
536		}
537	
538		if err := os.MkdirAll(filepath.Dir(pluginDir), 0755); err != nil {
539			return fmt.Errorf("creating plugins dir: %w", err)
540		}
541	
542		if err := os.Symlink(absPath, pluginDir); err != nil {
543			return fmt.Errorf("linking plugin into %s: %w", pluginDir, err)
544		}
545	
546		fmt.Fprintf(out, "Linked %s -> %s\n", pluginDir, absPath)
547	
548		entry := registry.InstalledEntry{
549			Name:    pkg.Name,
550			Version: pkg.Version,
551			Type:    pkg.Type,
552			Source:  absPath,
553		}
554		// Record entry.Files as project-relative paths when the plugin lives inside
555		// the working directory (in-tree mode). Convention-root and global absolute
556		// paths are recorded as-is. This keeps removeStaleFilesFromInstall
557		// compatible with relative paths recorded by prior runs.
558		fileToRecord := pluginDir
559		if f.WorkingDir != "" {
560			if rel, relErr := filepath.Rel(f.WorkingDir, pluginDir); relErr == nil && !strings.HasPrefix(rel, "..") {
561				fileToRecord = rel
562			}
563		}
564		entry.Files = append(entry.Files, fileToRecord)
565	
566		// Install local skills as symlinks into each supported harness surface.
567		// For global installs, skills land in the home directory; for project
568		// installs, they land in the project directory.
569		if len(pkg.Install.Skills) > 0 {
570			var absProject string
571			if global {
572				absProject, _ = os.UserHomeDir()
573			} else {
574				absProject = f.WorkingDir
575				if absProject == "" {
576					absProject, _ = os.Getwd()
577				}
578			}
579			if !filepath.IsAbs(absProject) {
580				absProject, _ = filepath.Abs(absProject)
581			}
582			writtenSkills, err := installLocalSkillSymlinks(absPath, absProject, pkg.Install.Skills, force)
583			if err != nil {
584				return fmt.Errorf("installing skills: %w", err)
585			}
586			entry.Files = append(entry.Files, writtenSkills...)
587		}
588	
589		// Copy CLI script if defined (skip if target is a developer symlink).
590		if pkg.Install.Scripts != nil {
591			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
592			if li, lErr := os.Lstat(dst); lErr == nil && li.Mode()&os.ModeSymlink != 0 {
593				target, _ := os.Readlink(dst)
594				fmt.Fprintf(out, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
595				entry.Files = append(entry.Files, dst)
596			} else {
597				copied, err := registry.CopyScriptFromRoot(pluginDir, pkg.Install.Scripts)
598				if err != nil {
599					fmt.Fprintf(out, "Warning: script copy error: %v\n", err)
600				} else {
601					entry.Files = append(entry.Files, copied)
602				}
603			}
604		}
605	
606		// Set execute bits on installed plugin files.
607		for _, rel := range pkg.Install.Executable {
608			p := filepath.Join(pluginDir, filepath.FromSlash(rel))
609			if info, err := os.Stat(p); err == nil && !info.IsDir() {
610				_ = os.Chmod(p, info.Mode()|0111)
611			}
612		}
613	
614		entry.InstalledAt = time.Now()
615	
616		removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
617		if removed > 0 {
618			fmt.Fprintf(out, "Removed %d stale file(s) from previous install\n", removed)
619		}
620	
621		// Git overlay hiding only applies to project-local installs (not global).
622		if !global {
623			if hidden, err := markLocalInstallOverlay(projectRoot, entry.Name, entry.Files); err != nil {
624				fmt.Fprintf(out, "Warning: local install is active but git overlay hiding failed: %v\n", err)
625			} else if hidden > 0 {
626				fmt.Fprintf(out, "Marked %d tracked local overlay file(s) skip-worktree\n", hidden)
627			}
628		}
629	
630		fmt.Fprintf(out, "Installed %s from local path %s — %d file(s); recorded plugin pin unchanged\n", entry.Name, absPath, len(entry.Files))
631		return nil
632	}
