634	func markLocalInstallOverlay(projectRoot, pluginName string, files []string) (int, error) {
635		if projectRoot == "" {
636			return 0, nil
637		}
638	
639		ctx := context.Background()
640		topOut, err := internalgit.Command(ctx, projectRoot, "rev-parse", "--show-toplevel").Output()
641		if err != nil {
642			return 0, nil
643		}
644		repoRoot := strings.TrimSpace(string(topOut))
645		if repoRoot == "" {
646			return 0, nil
647		}
648	
649		paths := localOverlayPaths(pluginName, files)
650		if len(paths) == 0 {
651			return 0, nil
652		}
653		if err := addLocalOverlayIgnores(repoRoot, paths); err != nil {
654			return 0, err
655		}
656	
657		args := append([]string{"ls-files", "-z", "--"}, paths...)
658		trackedOut, err := internalgit.Command(ctx, repoRoot, args...).Output()
659		if err != nil {
660			return 0, err
661		}
662		var tracked []string
663		for _, p := range strings.Split(string(trackedOut), "\x00") {
664			if p != "" {
665				tracked = append(tracked, p)
666			}
667		}
668		for start := 0; start < len(tracked); start += 100 {
669			end := start + 100
670			if end > len(tracked) {
671				end = len(tracked)
672			}
673			args := append([]string{"update-index", "--skip-worktree", "--"}, tracked[start:end]...)
674			if err := internalgit.Command(ctx, repoRoot, args...).Run(); err != nil {
675				return 0, err
676			}
677		}
678		return len(tracked), nil
679	}
