681	func localOverlayPaths(pluginName string, files []string) []string {
682		seen := map[string]bool{}
683		add := func(path string) {
684			path = filepath.ToSlash(strings.TrimSpace(path))
685			path = strings.TrimPrefix(path, "./")
686			if path == "" || strings.HasPrefix(path, "~") || filepath.IsAbs(path) {
687				return
688			}
689			if !seen[path] {
690				seen[path] = true
691			}
692		}
693	
694		add(filepath.ToSlash(ddxroot.JoinRelative("plugins", pluginName)))
695		for _, file := range files {
696			p := filepath.ToSlash(file)
697			for _, prefix := range []string{".agents/skills/", ".claude/skills/"} {
698				if strings.HasPrefix(p, prefix) {
699					rest := strings.TrimPrefix(p, prefix)
700					name := strings.Split(rest, "/")[0]
701					if name != "" {
702						add(prefix + name)
703					}
704				}
705			}
706		}
707	
708		paths := make([]string, 0, len(seen))
709		for p := range seen {
710			paths = append(paths, p)
711		}
712		sort.Strings(paths)
713		return paths
714	}
