716	func installLocalSkillSymlinks(pluginRoot, projectRoot string, mappings []registry.InstallMapping, force bool) ([]string, error) {
717		sourceRoots, err := localSkillSourceRoots(pluginRoot, mappings)
718		if err != nil {
719			return nil, err
720		}
721		if len(sourceRoots) == 0 {
722			return nil, nil
723		}
724	
725		var written []string
726		seenSkills := map[string]bool{}
727		for _, sourceRoot := range sourceRoots {
728			entries, err := os.ReadDir(sourceRoot)
729			if err != nil {
730				return nil, err
731			}
732			for _, entry := range entries {
733				if !entry.IsDir() && entry.Type()&os.ModeSymlink == 0 {
734					continue
735				}
736				name := entry.Name()
737				if seenSkills[name] {
738					continue
739				}
740				src := filepath.Join(sourceRoot, name)
741				if _, err := os.Stat(filepath.Join(src, "SKILL.md")); err != nil {
742					return nil, fmt.Errorf("%s: missing SKILL.md: %w", src, err)
743				}
744				for _, surface := range []string{".agents/skills", ".claude/skills"} {
745					dst := filepath.Join(projectRoot, filepath.FromSlash(surface), name)
746					if err := prepareSymlinkTarget(dst, force); err != nil {
747						return nil, err
748					}
749					if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
750						return nil, fmt.Errorf("creating skills dir: %w", err)
751					}
752					target, err := filepath.Rel(filepath.Dir(dst), src)
753					if err != nil {
754						target = src
755					}
756					if err := os.Symlink(target, dst); err != nil {
757						return nil, fmt.Errorf("linking skill %s -> %s: %w", dst, target, err)
758					}
759					written = append(written, filepath.Join(filepath.FromSlash(surface), name))
760				}
761				seenSkills[name] = true
762			}
763		}
764		return written, nil
765	}
