767	func localSkillSourceRoots(pluginRoot string, mappings []registry.InstallMapping) ([]string, error) {
768		var roots []string
769		seen := map[string]bool{}
770		for _, mapping := range mappings {
771			source := strings.TrimSpace(mapping.Source)
772			if source == "" {
773				continue
774			}
775			candidate := filepath.Clean(filepath.Join(pluginRoot, filepath.FromSlash(source)))
776			info, err := os.Stat(candidate)
777			if os.IsNotExist(err) {
778				continue
779			}
780			if err != nil {
781				return nil, err
782			}
783			if !info.IsDir() {
784				return nil, fmt.Errorf("%s: skill source is not a directory", candidate)
785			}
786			if seen[candidate] {
787				continue
788			}
789			seen[candidate] = true
790			roots = append(roots, candidate)
791		}
792		return roots, nil
793	}
