803	func loadLocalPluginManifestPackage(root, expectedName string) (*registry.Package, bool, error) {
804		for _, rel := range []string{
805			filepath.Join(".codex-plugin", "plugin.json"),
806			filepath.Join(".claude-plugin", "plugin.json"),
807		} {
808			path := filepath.Join(root, rel)
809			data, err := os.ReadFile(path)
810			if os.IsNotExist(err) {
811				continue
812			}
813			if err != nil {
814				return nil, false, fmt.Errorf("loading plugin manifest %s: %w", path, err)
815			}
816			var manifest localPluginJSONManifest
817			if err := json.Unmarshal(data, &manifest); err != nil {
818				return nil, false, fmt.Errorf("loading plugin manifest %s: invalid JSON: %w", path, err)
819			}
820			name := strings.TrimSpace(manifest.Name)
821			if name == "" {
822				name = expectedName
823			}
824			if name != expectedName {
825				return nil, false, fmt.Errorf("local package name %q does not match plugin manifest name %q", expectedName, name)
826			}
827			sources, err := pluginManifestSkillSources(manifest.Skills)
828			if err != nil {
829				return nil, false, fmt.Errorf("loading plugin manifest %s: %w", path, err)
830			}
831			pkg := &registry.Package{
832				Name:        name,
833				Version:     defaultString(strings.TrimSpace(manifest.Version), "local"),
834				Description: defaultString(strings.TrimSpace(manifest.Description), "local plugin package"),
835				Type:        registry.PackageTypePlugin,
836				Source:      defaultString(strings.TrimSpace(manifest.Repository), root),
837				Install: registry.PackageInstall{
838					Root: &registry.InstallMapping{
839						Source: ".",
840						Target: fmt.Sprintf(".ddx/plugins/%s", name),
841					},
842				},
843			}
844			for _, source := range sources {
845				pkg.Install.Skills = append(pkg.Install.Skills, registry.InstallMapping{
846					Source: source,
847					Target: ".agents/skills/",
848				})
849			}
850			return pkg, true, nil
851		}
852		return nil, false, nil
853	}
