855	func pluginManifestSkillSources(raw any) ([]string, error) {
856		switch v := raw.(type) {
857		case nil:
858			return nil, nil
859		case string:
860			source := cleanPluginManifestPath(v)
861			if source == "" {
862				return nil, nil
863			}
864			return []string{source}, nil
865		case []any:
866			var sources []string
867			for _, item := range v {
868				text, ok := item.(string)
869				if !ok {
870					return nil, fmt.Errorf("skills entries must be strings")
871				}
872				source := cleanPluginManifestPath(text)
873				if source != "" {
874					sources = append(sources, source)
875				}
876			}
877			return sources, nil
878		default:
879			return nil, fmt.Errorf("skills must be a string or array of strings")
880		}
881	}
