899	func addLocalOverlayIgnores(repoRoot string, paths []string) error {
900		excludePath := filepath.Join(repoRoot, ".git", "info", "exclude")
901		if err := os.MkdirAll(filepath.Dir(excludePath), 0o755); err != nil {
902			return err
903		}
904		existing, _ := os.ReadFile(excludePath)
905		text := string(existing)
906	
907		var additions []string
908		for _, p := range paths {
909			pattern := filepath.ToSlash(p)
910			candidates := []string{pattern}
911			if !strings.HasSuffix(pattern, "/") {
912				candidates = append(candidates, pattern+"/")
913			}
914			for _, candidate := range candidates {
915				if !strings.Contains(text, "\n"+candidate+"\n") && !strings.HasPrefix(text, candidate+"\n") {
916					additions = append(additions, candidate)
917				}
918			}
919		}
920		if len(additions) == 0 {
921			return nil
922		}
923	
924		var sb strings.Builder
925		if len(existing) > 0 && !strings.HasSuffix(text, "\n") {
926			sb.WriteString("\n")
927		}
928		if !strings.Contains(text, "# DDx local plugin overlays") {
929			sb.WriteString("\n# DDx local plugin overlays\n")
930		}
931		for _, pattern := range additions {
932			sb.WriteString(pattern)
933			sb.WriteString("\n")
934		}
935		return os.WriteFile(excludePath, append(existing, []byte(sb.String())...), 0o644)
936	}
