938	func filterLocalInstallValidationIssues(root string, issues []registry.ValidationIssue) []registry.ValidationIssue {
939		filtered := issues[:0]
940		roots := localInstallRootAliases(root)
941		ignoreCache := map[string]bool{}
942		for _, issue := range issues {
943			if rel, ok := localInstallIssueRel(roots, issue.Path); ok &&
944				(shouldSkipLocalInstallIssue(rel) || localInstallPathIsGitIgnored(root, rel, ignoreCache)) {
945				continue
946			}
947			filtered = append(filtered, issue)
948		}
949		return filtered
950	}
951	
952	// localInstallPathIsGitIgnored reports whether rel (a slash path relative to
953	// the local install source root) is gitignored in the source repository.
954	// ddx install --local must not fail validation on broken symlinks that live
955	// under gitignored scratch/tmp paths (e.g. doctor/home/.codex/tmp/...) the
956	// operator never intended to ship. Returns false when the source is not a git
957	// repo or git is unavailable, leaving the well-known-prefix skip list as the
958	// fallback.
959	func localInstallPathIsGitIgnored(root, rel string, cache map[string]bool) bool {
960		rel = strings.TrimSpace(rel)
961		if rel == "" {
962			return false
963		}
964		if cached, ok := cache[rel]; ok {
965			return cached
966		}
967		// git check-ignore exits 0 when the path is ignored, 1 when it is not, and
968		// 128 when the source is not a git repository — treat anything but 0 as
969		// "not ignored" so non-git sources fall through to the prefix skip list.
970		cmd := internalgit.Command(context.Background(), root, "check-ignore", "-q", "--", filepath.FromSlash(rel))
971		ignored := cmd.Run() == nil
972		cache[rel] = ignored
973		return ignored
974	}
