976	func localInstallRootAliases(root string) []string {
977		seen := map[string]bool{}
978		var roots []string
979		add := func(path string) {
980			if strings.TrimSpace(path) == "" {
981				return
982			}
983			abs, err := filepath.Abs(path)
984			if err != nil {
985				abs = path
986			}
987			if !seen[abs] {
988				seen[abs] = true
989				roots = append(roots, abs)
990			}
991			if resolved, err := filepath.EvalSymlinks(abs); err == nil && resolved != "" && !seen[resolved] {
992				seen[resolved] = true
993				roots = append(roots, resolved)
994			}
995		}
996		add(root)
997		return roots
998	}
