1000	func localInstallIssueRel(roots []string, path string) (string, bool) {
1001		for _, candidate := range localInstallPathAliases(path) {
1002			for _, root := range roots {
1003				rel, err := filepath.Rel(root, candidate)
1004				if err != nil || rel == "." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) || rel == ".." {
1005					continue
1006				}
1007				return filepath.ToSlash(rel), true
1008			}
1009		}
1010		return "", false
1011	}
