1013	func localInstallPathAliases(path string) []string {
1014		seen := map[string]bool{}
1015		var aliases []string
1016		add := func(candidate string) {
1017			if strings.TrimSpace(candidate) == "" {
1018				return
1019			}
1020			abs, err := filepath.Abs(candidate)
1021			if err != nil {
1022				abs = candidate
1023			}
1024			if !seen[abs] {
1025				seen[abs] = true
1026				aliases = append(aliases, abs)
1027			}
1028		}
1029		add(path)
1030		if resolved, err := filepath.EvalSymlinks(path); err == nil && resolved != "" {
1031			add(resolved)
1032		}
1033		dir := filepath.Dir(path)
1034		base := filepath.Base(path)
1035		if resolvedDir, err := filepath.EvalSymlinks(dir); err == nil && resolvedDir != "" {
1036			add(filepath.Join(resolvedDir, base))
1037		}
1038		return aliases
1039	}
