1042		rel = strings.TrimPrefix(filepath.ToSlash(rel), "./")
1043		for _, prefix := range []string{
1044			".git/",
1045			".ddx/plugins/",
1046			".ddx/agent-logs/",
1047			".ddx/executions/",
1048			".ddx/exec-runs.d/",
1049			".ddx/server/",
1050			".ddx/tsnet/",
1051			".ddx/workers/",
1052			"node_modules/",
1053			"tmp/",
1054			"website/node_modules/",
1055			"website/public/",
1056			"website/resources/",
1057			"website/test-results/",
1058			"website/playwright-report/",
1059		} {
1060			if strings.HasPrefix(rel, prefix) {
1061				return true
1062			}
1063		}
1064		return false
1065	}
