1158	func (f *CommandFactory) runVerify(cmd *cobra.Command, args []string) error {
1159		out := cmd.OutOrStdout()
1160	
1161		state, err := registry.LoadState()
1162		if err != nil {
1163			return fmt.Errorf("loading state: %w", err)
1164		}
1165	
1166		if len(state.Installed) == 0 {
1167			fmt.Fprintln(out, "No packages installed.")
1168			return nil
1169		}
1170	
1171		var totalIssues int
1172		for _, entry := range state.Installed {
1173			var issues []string
1174			for _, f := range entry.Files {
1175				expanded := registry.ExpandHome(f)
1176				info, err := os.Lstat(expanded)
1177				if os.IsNotExist(err) {
1178					issues = append(issues, fmt.Sprintf("  missing: %s", f))
1179					continue
1180				}
1181				if err != nil {
1182					issues = append(issues, fmt.Sprintf("  error: %s: %v", f, err))
1183					continue
1184				}
1185				// Check symlinks resolve.
1186				if info.Mode()&os.ModeSymlink != 0 {
1187					target, err := os.Readlink(expanded)
1188					if err != nil {
1189						issues = append(issues, fmt.Sprintf("  broken symlink: %s", f))
1190						continue
1191					}
1192					// Resolve relative symlinks against their parent directory.
1193					if !filepath.IsAbs(target) {
1194						target = filepath.Join(filepath.Dir(expanded), target)
1195					}
1196					if _, err := os.Stat(target); os.IsNotExist(err) {
1197						issues = append(issues, fmt.Sprintf("  broken symlink: %s -> %s", f, target))
1198					}
1199				}
1200			}
1201	
1202			if len(issues) == 0 {
1203				fmt.Fprintf(out, "%s %s: OK (%d files)\n", entry.Name, entry.Version, len(entry.Files))
1204			} else {
1205				fmt.Fprintf(out, "%s %s: %d issue(s)\n", entry.Name, entry.Version, len(issues))
1206				for _, issue := range issues {
1207					fmt.Fprintln(out, issue)
1208				}
1209				totalIssues += len(issues)
1210			}
1211		}
1212	
1213		if totalIssues > 0 {
1214			return fmt.Errorf("%d integrity issue(s) found — run 'ddx install <name> --force' to repair", totalIssues)
1215		}
1216		return nil
1217	}
