1219	// newSearchCommand creates the "ddx search <query>" command.
1220	func (f *CommandFactory) newSearchCommand() *cobra.Command {
1221		return &cobra.Command{
1222			Use:   "search <query>",
1223			Short: "Search available packages",
1224			Long:  `Search the DDx registry for packages matching the given query.`,
1225			Args:  cobra.ExactArgs(1),
1226			RunE:  f.runSearch,
1227		}
1228	}
1229	
1230	func (f *CommandFactory) runSearch(cmd *cobra.Command, args []string) error {
1231		query := args[0]
1232		out := cmd.OutOrStdout()
1233	
1234		reg := registry.BuiltinRegistry()
1235		results := reg.Search(query)
1236	
1237		if len(results) == 0 {
1238			fmt.Fprintf(out, "No packages found matching %q\n", query)
1239			return nil
1240		}
1241	
1242		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
1243		fmt.Fprintln(w, "NAME\tVERSION\tTYPE\tDESCRIPTION")
1244		for _, pkg := range results {
1245			fmt.Fprintf(w, "%s\t%s\t%s\t%s\n",
1246				pkg.Name,
1247				pkg.Version,
1248				string(pkg.Type),
1249				pkg.Description,
1250			)
1251		}
1252		return w.Flush()
1253	}
1254	
1255	func (f *CommandFactory) newOutdatedCommand() *cobra.Command {
1256		cmd := &cobra.Command{
1257			Use:   "outdated",
1258			Short: "List installed packages with available updates",
1259			Long:  `Check installed packages against the registry and list those with newer versions available.`,
1260			Args:  cobra.NoArgs,
1261			RunE:  f.runOutdated,
1262		}
1263		cmd.Flags().Bool("json", false, "Output as JSON")
1264		return cmd
1265	}
1266	
1267	func (f *CommandFactory) runOutdated(cmd *cobra.Command, args []string) error {
1268		out := cmd.OutOrStdout()
1269		asJSON, _ := cmd.Flags().GetBool("json")
1270	
1271		state, err := registry.LoadState()
1272		if err != nil {
1273			return fmt.Errorf("reading installed state: %w", err)
1274		}
1275		if len(state.Installed) == 0 {
1276			fmt.Fprintln(out, "No packages installed.")
1277			return nil
1278		}
1279	
1280		reg := registry.BuiltinRegistry()
1281	
1282		type outdatedEntry struct {
1283			Name             string `json:"name"`
1284			InstalledVersion string `json:"installed_version"`
1285			LatestVersion    string `json:"latest_version"`
1286		}
1287	
1288		var outdated []outdatedEntry
1289		for _, entry := range state.Installed {
1290			pkg, err := reg.Find(entry.Name)
1291			if err != nil {
1292				continue // not in registry, skip
1293			}
1294			if pkg.Version != entry.Version {
1295				outdated = append(outdated, outdatedEntry{
1296					Name:             entry.Name,
1297					InstalledVersion: entry.Version,
1298					LatestVersion:    pkg.Version,
1299				})
1300			}
1301		}
1302	
1303		if len(outdated) == 0 {
1304			fmt.Fprintln(out, "All installed packages are up to date.")
1305			return nil
1306		}
1307	
1308		if asJSON {
1309			enc := json.NewEncoder(out)
1310			enc.SetIndent("", "  ")
1311			return enc.Encode(outdated)
1312		}
1313	
1314		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
1315		fmt.Fprintln(w, "NAME\tINSTALLED\tLATEST")
1316		for _, o := range outdated {
1317			fmt.Fprintf(w, "%s\t%s\t%s\n", o.Name, o.InstalledVersion, o.LatestVersion)
1318		}
1319		return w.Flush()
1320	}
