73	// authoritative. Otherwise DDx falls back to an XDG-scoped convention root
74	// derived from the project's canonical git remote, or a deterministic local
75	// identity.
76	func Path(ctx context.Context, projectRoot string) string {
77		inTree := InTree(projectRoot)
78		if info, err := os.Stat(inTree); err == nil && info.IsDir() {
79			return inTree
80		}
81		root := filepath.Join(projectsRoot(), projectIdentity(ctx, projectRoot))
82		_ = bootstrapConventionRoot(ctx, projectRoot, root)
