111	func SetMasterWorktree(ctx context.Context, projectRoot, masterPath string) error {
112		if ctx == nil {
113			ctx = context.Background()
114		}
115	
116		root := Path(ctx, projectRoot)
117		return withBootstrapLock(root, func() error {
118			registryPath := filepath.Join(root, "worktrees.json")
119			registry, err := readWorktreeRegistry(registryPath)
120			if err != nil {
121				return err
122			}
123	
124			canonicalPath, err := canonicalWorktreePath(masterPath)
125			if err != nil {
126				return err
127			}
128	
129			now := time.Now().UTC().Format(time.RFC3339Nano)
130			hostname, err := os.Hostname()
131			if err != nil || strings.TrimSpace(hostname) == "" {
132				hostname = "unknown"
133			}
134	
135			changed := upsertWorktreeRegistryEntry(&registry, canonicalPath, now, hostname)
136			if registry.Master != canonicalPath {
137				registry.Master = canonicalPath
138				changed = true
139			}
140			if !changed {
141				return nil
142			}
143			return writeWorktreeRegistry(registryPath, registry)
144		})
145	}
