238	const bootstrapCommitMessage = "chore: bootstrap ddx state"
239	
240	var bootstrapLockStaleAge = 2 * time.Minute
241	
242	type worktreeRegistry struct {
243		Paths  []worktreeRegistryEntry `json:"paths"`
244		Master string                  `json:"master"`
245	}
246	
247	type worktreeRegistryEntry struct {
248		Path        string `json:"path"`
249		FirstSeenAt string `json:"first_seen_at"`
250		LastSeenAt  string `json:"last_seen_at"`
251		Hostname    string `json:"hostname"`
252	}
253	
254	func bootstrapConventionRoot(ctx context.Context, projectRoot, root string) error {
255		if ctx == nil {
256			ctx = context.Background()
257		}
258		return withBootstrapLock(root, func() error {
259			if err := os.MkdirAll(root, 0o755); err != nil {
260				return err
261			}
262			if err := ensureGitRepo(ctx, root); err != nil {
263				return err
264			}
265			changed, err := ensureWorktreeRegistry(projectRoot, root)
266			if err != nil {
267				return err
268			}
269			if err := ensureHeadCommit(ctx, root, changed); err != nil {
270				return err
271			}
272			return nil
273		})
274	}
275	
276	func withBootstrapLock(root string, fn func() error) error {
277		lockDir := root + ".bootstrap.lock"
278		if err := os.MkdirAll(filepath.Dir(lockDir), 0o755); err != nil {
279			return err
280		}
281		deadline := time.Now().Add(30 * time.Second)
282		for {
283			err := os.Mkdir(lockDir, 0o755)
284			if err == nil {
285				_ = os.WriteFile(filepath.Join(lockDir, "pid"), []byte(strconv.Itoa(os.Getpid())), 0o644)
286				_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"), []byte(time.Now().UTC().Format(time.RFC3339Nano)), 0o644)
287				defer os.RemoveAll(lockDir)
288				return fn()
289			}
290			if breakStaleBootstrapLock(lockDir) {
291				continue
292			}
293			if time.Now().After(deadline) {
294				return err
295			}
296			time.Sleep(25 * time.Millisecond)
297		}
298	}
299	
300	func breakStaleBootstrapLock(lockDir string) bool {
301		acquiredAt, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
302		if err == nil {
303			if ts, parseErr := time.Parse(time.RFC3339Nano, strings.TrimSpace(string(acquiredAt))); parseErr == nil && time.Since(ts) > bootstrapLockStaleAge {
304				_ = os.RemoveAll(lockDir)
305				return true
306			}
307		}
308		return false
309	}
310	
311	func ensureGitRepo(ctx context.Context, root string) error {
312		if out, err := gitpkg.Command(ctx, root, "rev-parse", "--git-dir").CombinedOutput(); err == nil {
313			_ = out
314			return nil
315		}
316		out, err := gitpkg.Command(ctx, root, "init").CombinedOutput()
317		if err != nil {
318			return newGitError("git init", out, err)
319		}
320		return nil
321	}
322	
323	func ensureWorktreeRegistry(projectRoot, root string) (bool, error) {
324		worktreePath, err := canonicalWorktreePath(projectRoot)
325		if err != nil {
326			return false, err
327		}
328	
329		registryPath := filepath.Join(root, "worktrees.json")
330		registry, err := readWorktreeRegistry(registryPath)
331		if err != nil {
332			return false, err
333		}
334	
335		now := time.Now().UTC().Format(time.RFC3339Nano)
336		hostname, err := os.Hostname()
337		if err != nil || strings.TrimSpace(hostname) == "" {
338			hostname = "unknown"
339		}
340	
341		changed := upsertWorktreeRegistryEntry(&registry, worktreePath, now, hostname)
342		if registry.Master == "" {
343			registry.Master = worktreePath
344			changed = true
345		}
346		if !changed {
347			return false, nil
348		}
349		return true, writeWorktreeRegistry(registryPath, registry)
350	}
351	
352	func upsertWorktreeRegistryEntry(registry *worktreeRegistry, worktreePath, now, hostname string) bool {
353		for i := range registry.Paths {
354			if registry.Paths[i].Path != worktreePath {
355				continue
356			}
357			changed := false
358			if registry.Paths[i].FirstSeenAt == "" {
359				registry.Paths[i].FirstSeenAt = now
360				changed = true
361			}
362			if registry.Paths[i].LastSeenAt != now {
363				if registry.Paths[i].LastSeenAt == "" {
364					registry.Paths[i].LastSeenAt = registry.Paths[i].FirstSeenAt
365				}
366				if registry.Paths[i].LastSeenAt != now {
367					registry.Paths[i].LastSeenAt = now
368				}
369				changed = true
370			}
371			if registry.Paths[i].Hostname == "" {
372				registry.Paths[i].Hostname = hostname
373				changed = true
374			}
375			return changed
376		}
377	
378		registry.Paths = append(registry.Paths, worktreeRegistryEntry{
379			Path:        worktreePath,
380			FirstSeenAt: now,
381			LastSeenAt:  now,
382			Hostname:    hostname,
383		})
384		return true
385	}
386	
387	func canonicalWorktreePath(projectRoot string) (string, error) {
388		abs, err := filepath.Abs(projectRoot)
389		if err != nil {
390			return "", err
391		}
392		return filepath.Clean(abs), nil
393	}
394	
395	func readWorktreeRegistry(path string) (worktreeRegistry, error) {
396		data, err := os.ReadFile(path)
397		if err != nil {
398			if os.IsNotExist(err) {
399				return worktreeRegistry{}, nil
400			}
401			return worktreeRegistry{}, err
402		}
403		if len(data) == 0 {
404			return worktreeRegistry{}, nil
405		}
406		var registry worktreeRegistry
407		if err := json.Unmarshal(data, &registry); err != nil {
408			return worktreeRegistry{}, err
409		}
410		return registry, nil
411	}
412	
413	func writeWorktreeRegistry(path string, registry worktreeRegistry) error {
414		data, err := json.MarshalIndent(registry, "", "  ")
415		if err != nil {
416			return err
417		}
418		data = append(data, '\n')
419		tmp := path + ".tmp"
420		if err := os.WriteFile(tmp, data, 0o644); err != nil {
421			return err
422		}
423		return os.Rename(tmp, path)
424	}
425	
426	func ensureHeadCommit(ctx context.Context, root string, stageRegistry bool) error {
427		if headExists(ctx, root) {
428			return nil
429		}
430		if stageRegistry {
431			out, err := gitpkg.Command(ctx, root, "add", "worktrees.json").CombinedOutput()
432			if err != nil {
433				return newGitError("git add worktrees.json", out, err)
434			}
435		}
436		out, err := gitpkg.Command(
437			ctx,
438			root,
439			"-c", "user.name=DDx Bootstrap",
440			"-c", "user.email=ddx-bootstrap@localhost",
441			"-c", "commit.gpgsign=false",
442			"commit", "--allow-empty", "-m", bootstrapCommitMessage,
443		).CombinedOutput()
444		if err != nil {
445			return newGitError("git commit", out, err)
446		}
447		return nil
448	}
449	
450	func headExists(ctx context.Context, root string) bool {
451		return gitpkg.Command(ctx, root, "rev-parse", "--verify", "HEAD^{commit}").Run() == nil
452	}
453	
454	func newGitError(op string, out []byte, err error) error {
455		msg := strings.TrimSpace(string(out))
456		if msg == "" {
457			return err
458		}
459		return &gitOperationError{op: op, msg: msg, err: err}
460	}
461	
462	type gitOperationError struct {
463		op  string
464		msg string
465		err error
466	}
467	
468	func (e *gitOperationError) Error() string {
469		return e.op + ": " + e.msg
470	}
471	
472	func (e *gitOperationError) Unwrap() error {
473		return e.err
474	}
